mapper.select:
SELECT a.bom_id as bomId ,a.item_cd ,a.bom_ver ,b.item_name ,b.unit ,req.qty ,b.item_type_cd FROM tb_bom_mst a INNER JOIN tb_item_mst b ON b.item_cd = a.item_cd INNER JOIN (
SELECT #{item.itemCd} AS item_cd, #{item.qty} AS qty
) req ON req.item_cd = a.item_cd WHERE a.default_yn = 'Y'

with tmp_bom_recipe as ( select x.item_cd, sum(x.reqQty) as reqQty from (
select b.item_cd, case when c.item_type_cd = 'M1' then sum(b.real_content) * #{item.qty} / 100 else sum(b.qty) * #{item.qty} / 100 end as reqQty from tb_bom_mst a join tb_bom_recipe b on a.bom_id = b.bom_id join tb_item_mst c on c.item_cd = b.item_cd where a.default_yn = 'Y' and a.bom_id = #{item.bomId} and b.item_cd not in ('JRW00215', 'JRMSC00011') group by b.item_cd, c.item_type_cd
) x group by x.item_cd ) select a.item_cd as itemCd ,b.item_name as itemName ,b.spec ,isnull(c.realStockQty, 0) as realStockQty ,a.reqQty ,isnull(d.reserveStockQty, 0) as reserveStockQty ,isnull(c.realStockQty, 0) - a.reqQty as differenceQty ,e.customer_name as customerName ,isnull(dbo.getCommonName('ITEM_GRP1', b.item_grp1 ), '') as orderType ,b.customer_cd as customerCd from tmp_bom_recipe a inner join tb_item_mst b on a.item_cd = b.item_cd left join ( select item_cd ,sum(qty) as realStockQty from vw_inv_stock_tran c group by item_cd ) c on c.item_cd = a.item_cd left join ( select item_cd ,sum(qty) as reserveStockQty from tb_pur_order_item where in_yn ='N' group by item_cd ) d on d.item_cd = a.item_cd left join tb_customer e on e.customer_cd = b.customer_cd order by e.customer_name desc
